import { useState, useEffect, useCallback } from 'react';

import constFlaskURL from './constFlaskURL'


function TableData () {
    const [tableData, setTableData] = useState([]);

    const fetchTableData = useCallback(async (endpoint) => {
        try {
            const response = await constFlaskURL.get(endpoint);

            if (response.status === 200) {
                setTableData(Array.isArray(response.data) ? response.data : [response.data]);
            }
        } catch (err) {
            console.log(err);
        }
    }, []);

    useEffect(() => {
        fetchTableData();
    }, [fetchTableData]);

};

export default TableData;
